import { realpathSync, statSync } from "node:fs";
import { relative } from "node:path";

import type {
  ElementInfo,
  PropValue,
} from "../../modules/annotation/annotate-file.ts";
import { sourceVersionHash } from "../../modules/annotation/source-version.ts";

export const DEFAULT_EXCLUDE = ["**/node_modules/**"] as const;

/**
 * Static per-component declaration of whether a custom component accepts
 * `children`. Supplied by callers that know this from a fixed table (e.g. the
 * Expo plugin's React Native host-component overrides). The Vite/Next.js
 * plugins supply no overrides — custom components are left without a
 * `supports-children` flag and consumers treat their support as unknown.
 */
export interface ElementTypeSupport {
  supportsChildren: boolean;
}

/** HTML void elements that cannot have children (self-closing only). */
export const HTML_VOID_ELEMENTS = new Set([
  "area",
  "base",
  "br",
  "col",
  "embed",
  "hr",
  "img",
  "input",
  "link",
  "meta",
  "param",
  "source",
  "track",
  "wbr",
]);

export type ComputeAnnotatedProps = (
  info: ElementInfo,
  filepath: string,
  modifiedtsMs: number,
  sourceVersion: string,
) => Record<string, PropValue>;

export function cleanModuleId(id: string): string {
  return id.replace(/[?#].*$/, "");
}

export function resolveCanonicalRoot(root: string): string {
  try {
    return realpathSync.native(root);
  } catch {
    return root;
  }
}

export function isIntrinsicElement(tagName: string): boolean {
  return tagName.length > 0 && tagName[0] === tagName[0]!.toLowerCase();
}

export function hasJsxAttribute(info: ElementInfo, attrName: string): boolean {
  for (const attr of info.element.openingElement.attributes) {
    const name = (attr as { name?: { name?: unknown } }).name;
    if (name?.name === attrName) return true;
  }
  return false;
}

export function defaultComputeAnnotatedProps(
  info: ElementInfo,
  filepath: string,
  modifiedtsMs: number,
  sourceVersion: string,
): Record<string, PropValue> {
  return {
    "data-tempo-filepath": filepath,
    "data-tempo-position": info.element.openingElement.start,
    "data-tempo-modifiedts": modifiedtsMs,
    // Content-hash identity of the file this element was annotated from. The
    // canvas reconcile loop equality-compares it against the write pipeline's
    // computed version to decide whether a capture reflects a given edit.
    "data-tempo-source-version": sourceVersion,
  };
}

export function computeTempoAnnotatedProps(params: {
  info: ElementInfo;
  filepath: string;
  modifiedtsMs: number;
  sourceVersion: string;
  computeAnnotatedProps?: ComputeAnnotatedProps;
  elementSupportOverrides?: ReadonlyMap<string, ElementTypeSupport>;
}): Record<string, PropValue> {
  const {
    info,
    filepath,
    modifiedtsMs,
    sourceVersion,
    computeAnnotatedProps,
    elementSupportOverrides,
  } = params;

  const userProps = computeAnnotatedProps
    ? computeAnnotatedProps(info, filepath, modifiedtsMs, sourceVersion)
    : defaultComputeAnnotatedProps(info, filepath, modifiedtsMs, sourceVersion);

  if (isIntrinsicElement(info.tagName)) {
    return {
      ...userProps,
      "data-tempo-supports-children": hasJsxAttribute(
        info,
        "data-tempo-supports-children",
      )
        ? undefined
        : !HTML_VOID_ELEMENTS.has(info.tagName),
    };
  }

  const override = elementSupportOverrides?.get(info.tagName);
  if (override) {
    return {
      ...userProps,
      "data-tempo-supports-children": hasJsxAttribute(
        info,
        "data-tempo-supports-children",
      )
        ? undefined
        : override.supportsChildren,
    };
  }

  // Custom component with no static override: emit no `data-tempo-supports-*`
  // flags. Determining them required a per-file TypeScript program, which was
  // removed for being the dominant cost of devserver startup. Consumers treat
  // the absent flags as "unknown" and fall back to their own defaults.
  return userProps;
}

export function getFileAnnotationContext(params: {
  source: string;
  filename: string;
  root: string;
  canonicalizeFilename?: boolean;
}): {
  cleanFilename: string;
  filepath: string;
  modifiedtsMs: number;
  sourceVersion: string;
} {
  const rawCleanFilename = cleanModuleId(params.filename);
  let cleanFilename = rawCleanFilename;
  if (params.canonicalizeFilename) {
    try {
      cleanFilename = realpathSync.native(rawCleanFilename);
    } catch {
      cleanFilename = rawCleanFilename;
    }
  }
  return {
    cleanFilename,
    filepath: relative(params.root, cleanFilename),
    modifiedtsMs: Math.trunc(statSync(cleanFilename).mtimeMs),
    // Hashed once per file per transform (the context is built once, reused
    // for every element) so the per-element funnel just forwards the token.
    sourceVersion: sourceVersionHash(params.source),
  };
}
